import React, { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import API from '../utils/api';

export default function Profile() {
  const { user, setUser } = useAuth();
  const [form, setForm] = useState({
    name: '', bio: '', college: '', graduation: '', github: '', linkedin: '', portfolio: '', avatar: ''
  });
  const [loading, setLoading] = useState(false);
  const [editing, setEditing] = useState(false);
  const [stats, setStats] = useState({ skills: 0, projects: 0, internships: 0 });

  useEffect(() => {
    if (user) {
      setForm({
        name: user.name || '', bio: user.bio || '', college: user.college || '',
        graduation: user.graduation || '', github: user.github || '',
        linkedin: user.linkedin || '', portfolio: user.portfolio || '', avatar: user.avatar || ''
      });
    }
    // Fetch counts
    Promise.all([API.get('/skills'), API.get('/projects'), API.get('/internships')])
      .then(([s, p, i]) => setStats({ skills: s.data.length, projects: p.data.length, internships: i.data.length }))
      .catch(() => {});
  }, [user]);

  const handleSave = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await API.put('/profile', form);
      setUser(res.data);
      localStorage.setItem('user', JSON.stringify(res.data));
      toast.success('Profile updated!');
      setEditing(false);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed');
    } finally {
      setLoading(false);
    }
  };

  const initial = form.name?.[0]?.toUpperCase() || '?';

  return (
    <>
      <div className="page-header">
        <h1 className="page-title">👤 Profile</h1>
        <p className="page-subtitle">Manage your personal information and social links</p>
      </div>

      <div className="page-body">
        {/* Hero */}
        <div className="profile-hero">
          <div className="profile-avatar-large">
            {form.avatar ? <img src={form.avatar} alt="" onError={e => { e.target.style.display = 'none'; }} /> : initial}
          </div>
          <div style={{ flex: 1 }}>
            <h2 style={{ fontSize: 24, fontWeight: 800, marginBottom: 4 }}>{form.name || 'Your Name'}</h2>
            <p style={{ color: 'var(--text-muted)', fontSize: 14, marginBottom: 8 }}>{user?.email}</p>
            {form.bio && <p style={{ color: 'var(--text-muted)', fontSize: 14, maxWidth: 480, lineHeight: 1.6 }}>{form.bio}</p>}
            <div style={{ display: 'flex', gap: 8, marginTop: 12, flexWrap: 'wrap' }}>
              {form.college && <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>🎓 {form.college}</span>}
              {form.graduation && <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>📅 Class of {form.graduation}</span>}
            </div>
            <div style={{ display: 'flex', gap: 10, marginTop: 12, flexWrap: 'wrap' }}>
              {form.github && <a href={form.github} target="_blank" rel="noreferrer" className="project-link github" style={{ textDecoration: 'none' }}>
                <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor"><path d="M12 0C5.37 0 0 5.37 0 12c0 5.3 3.438 9.8 8.205 11.385.6.113.82-.258.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61C4.422 18.07 3.633 17.7 3.633 17.7c-1.087-.744.084-.729.084-.729 1.205.084 1.838 1.236 1.838 1.236 1.07 1.835 2.809 1.305 3.495.998.108-.776.417-1.305.76-1.605-2.665-.3-5.466-1.332-5.466-5.93 0-1.31.465-2.38 1.235-3.22-.135-.303-.54-1.523.105-3.176 0 0 1.005-.322 3.3 1.23.96-.267 1.98-.399 3-.405 1.02.006 2.04.138 3 .405 2.28-1.552 3.285-1.23 3.285-1.23.645 1.653.24 2.873.12 3.176.765.84 1.23 1.91 1.23 3.22 0 4.61-2.805 5.625-5.475 5.92.42.36.81 1.096.81 2.22 0 1.606-.015 2.896-.015 3.286 0 .315.21.69.825.57C20.565 21.795 24 17.295 24 12c0-6.63-5.37-12-12-12"/></svg>
                GitHub
              </a>}
              {form.linkedin && <a href={form.linkedin} target="_blank" rel="noreferrer" className="project-link linkedin" style={{ textDecoration: 'none' }}>
                <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor"><path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 0 1-2.063-2.065 2.064 2.064 0 1 1 2.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z"/></svg>
                LinkedIn
              </a>}
              {form.portfolio && <a href={form.portfolio} target="_blank" rel="noreferrer" className="project-link live" style={{ textDecoration: 'none' }}>🌐 Portfolio</a>}
            </div>
          </div>
          <button className="btn btn-secondary" onClick={() => setEditing(v => !v)}>
            {editing ? '✕ Cancel' : '✏️ Edit Profile'}
          </button>
        </div>

        {/* Stats row */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16, marginBottom: 24 }}>
          {[
            { label: 'Skills', value: stats.skills, icon: '⚡', color: '#2563eb' },
            { label: 'Projects', value: stats.projects, icon: '🛠️', color: '#0ea5e9' },
            { label: 'Applications', value: stats.internships, icon: '💼', color: '#8b5cf6' },
          ].map(s => (
            <div key={s.label} className="card" style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 28, marginBottom: 4 }}>{s.icon}</div>
              <div style={{ fontSize: 32, fontWeight: 800, color: s.color, fontFamily: 'Space Grotesk, sans-serif' }}>{s.value}</div>
              <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>{s.label}</div>
            </div>
          ))}
        </div>

        {/* Edit form */}
        {editing && (
          <div className="card" style={{ animation: 'slideUp 0.3s ease' }}>
            <h3 style={{ fontSize: 16, fontWeight: 700, marginBottom: 20 }}>✏️ Edit Your Information</h3>
            <form onSubmit={handleSave}>
              <div className="grid-2" style={{ gap: 14 }}>
                <div className="form-group">
                  <label className="form-label">Full Name</label>
                  <input className="form-input" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Avatar URL</label>
                  <input className="form-input" type="url" placeholder="https://..." value={form.avatar} onChange={e => setForm(f => ({ ...f, avatar: e.target.value }))} />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Bio</label>
                <textarea className="form-input" placeholder="Tell us about yourself..." value={form.bio} onChange={e => setForm(f => ({ ...f, bio: e.target.value }))} />
              </div>
              <div className="grid-2" style={{ gap: 14 }}>
                <div className="form-group">
                  <label className="form-label">College / University</label>
                  <input className="form-input" placeholder="MIT, Stanford..." value={form.college} onChange={e => setForm(f => ({ ...f, college: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Graduation Year</label>
                  <input className="form-input" placeholder="2026" value={form.graduation} onChange={e => setForm(f => ({ ...f, graduation: e.target.value }))} />
                </div>
              </div>
              <div className="grid-2" style={{ gap: 14 }}>
                <div className="form-group">
                  <label className="form-label">GitHub Profile URL</label>
                  <input className="form-input" type="url" placeholder="https://github.com/..." value={form.github} onChange={e => setForm(f => ({ ...f, github: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">LinkedIn Profile URL</label>
                  <input className="form-input" type="url" placeholder="https://linkedin.com/in/..." value={form.linkedin} onChange={e => setForm(f => ({ ...f, linkedin: e.target.value }))} />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Portfolio Website</label>
                <input className="form-input" type="url" placeholder="https://yourportfolio.com" value={form.portfolio} onChange={e => setForm(f => ({ ...f, portfolio: e.target.value }))} />
              </div>
              <div style={{ display: 'flex', gap: 10 }}>
                <button type="button" className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setEditing(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ flex: 2 }} disabled={loading}>
                  {loading ? '⏳ Saving...' : '💾 Save Changes'}
                </button>
              </div>
            </form>
          </div>
        )}

        {!editing && (
          <div className="card">
            <h3 style={{ fontSize: 15, fontWeight: 700, marginBottom: 16 }}>📋 Account Details</h3>
            <div style={{ display: 'grid', gap: 12 }}>
              {[
                { label: 'Email', value: user?.email, icon: '📧' },
                { label: 'College', value: form.college || '—', icon: '🎓' },
                { label: 'Graduation', value: form.graduation ? `Class of ${form.graduation}` : '—', icon: '📅' },
                { label: 'Portfolio', value: form.portfolio || '—', icon: '🌐', link: form.portfolio },
              ].map(f => (
                <div key={f.label} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 14px', background: 'var(--bg)', borderRadius: 10, border: '1px solid var(--border)' }}>
                  <span style={{ fontSize: 18 }}>{f.icon}</span>
                  <div>
                    <div style={{ fontSize: 11, color: 'var(--text-dim)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' }}>{f.label}</div>
                    {f.link
                      ? <a href={f.link} target="_blank" rel="noreferrer" style={{ color: 'var(--primary-light)', fontSize: 14, textDecoration: 'none' }}>{f.value}</a>
                      : <div style={{ color: 'var(--text)', fontSize: 14 }}>{f.value}</div>
                    }
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </>
  );
}
